import { ColorPalette } from '../../core/types/color-palette.js';
import { colorPaletteMap } from '../../core/types/color-palettes-definitions.js';

export const getColorsList = (colorPalette: ColorPalette) => {
  const categories = Object.keys(colorPaletteMap[colorPalette]);
  return categories.map((category) => colorPaletteMap[colorPalette][category]);
};
